function [ttlA,ttlB,lblP] = fLabelPhosOvV01(nmbStep)%% function label for esm overview%% [ttlA,ttlS,lblP] = fLabelEsmovV01()% gives you labels%% ttlA: title for angle text output% ttlS: title for spectrumd text output% lblP: lable for image plot%% Kei Nakamura% Created on Tuesday, December 7th 2010.% Modified on %% ver.1: %% main body%% label for position txt outputttlA = cell(5*nmbStep,1);ttlB = cell(5*nmbStep,1);ttlA{1} = 'x_mm';ttlA{2} = 'charge_pC/mm';ttlA{3} = 'charge+std_pC/mm';ttlA{4} = 'charge-std_pC/mm';ttlA{5} = 'std_pC/mm';ttlB = ttlA;ttlB{1} = 'y_mm';for ii=1:nmbStep-1    ttlA(ii*5+1:(ii+1)*5) = ttlA(1:5);    ttlB(ii*5+1:(ii+1)*5) = ttlB(1:5);end%% label for plotlblP{1} = 'mrad';lblP{2} = 'MeV';
